 19	type LogsProps = {
 20	  resource: PodKind;
 21	  containers: ContainerSpec[];
 22	  setCurrentLogsGetter?: (getter: () => string) => void;
 23	  activeStep?: string;
 24	  taskName?: string;
 25	  stillFetching?: boolean;
 26	  isResourceManagedByKueue?: boolean;
 27	  pipelineRunName?: string;
 28	  pipelineRunFinished?: boolean;
 29	};
 30	
 31	type LogData = {
 32	  [containerName: string]: {
 33	    logs: string[];
 34	    status: string;
 35	  };
 36	};
 37	
 38	const processLogData = (
 39	  logData: LogData,
 40	  containers: ContainerSpec[],
 41	): string => {
 42	  let result = '';
 43	
 44	  containers.map(({ name: containerName }) => {
 45	    if (logData[containerName]) {
 46	      const { logs } = logData[containerName];
 47	      const uniqueLogs = Array.from(new Set(logs));
 48	      const filteredLogs = uniqueLogs.filter((log) => log.trim() !== '');
 49	      const formattedContainerName = `${containerName.toUpperCase()}`;
 50	
 51	      if (filteredLogs.length === 0) {
 52	        result += `${formattedContainerName}\n\n`;
 53	      } else {
 54	        const joinedLogs = filteredLogs.join('\n');
 55	        result += `${formattedContainerName}\n${joinedLogs}\n\n`;
 56	      }
 57	    }
 58	  });
 59	  return result;
 60	};
 61	
 62	const Logs: React.FC<LogsProps> = ({
 63	  stillFetching,
 64	  resource,
 65	  taskName,
 66	  containers,
 67	  setCurrentLogsGetter,
 68	  activeStep,
 69	  isResourceManagedByKueue,
 70	  pipelineRunName,
 71	  pipelineRunFinished,
 72	}) => {
 73	  if (!resource) return null;
 74	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 75	  const { metadata = {} } = resource;
 76	  const { name: resName, namespace: resNamespace } = metadata;
 77	  const [error, setError] = React.useState<boolean>(false);
 78	  const [logData, setLogData] = React.useState<LogData>({});
 79	  const [formattedLogString, setFormattedLogString] = React.useState('');
 80	  const [scrollToRow, setScrollToRow] = React.useState<number>(0);
 81	  const [activeContainers, setActiveContainers] = React.useState<Set<string>>(
 82	    new Set(),
 83	  );
 84	
 85	  // Ref to track current pipelineRunFinished value for WebSocket retry logic
 86	  const pipelineRunFinishedRef = React.useRef(pipelineRunFinished);
 87	  React.useEffect(() => {
 88	    pipelineRunFinishedRef.current = pipelineRunFinished;
 89	  }, [pipelineRunFinished]);
 90	
 91	  const findTargetRowForActiveStep = React.useMemo(
 92	    () => (formattedString: string) => {
 93	      if (!activeStep) return null;
 94	      const lines = formattedString.split('\n');
 95	      let targetLine: number | null = null;
 96	      for (let i = 0; i < lines.length; i++) {
 97	        const line = lines[i];
 98	        if (line.includes(`STEP-${activeStep}`.toUpperCase())) {
 99	          targetLine = i;
100	          break;
101	        }
102	      }
103	      return targetLine;
104	    },
105	    [activeStep],
106	  );
107	
108	  React.useEffect(() => {
109	    setCurrentLogsGetter(() => {
110	      return formattedLogString;
111	    });
112	  }, [setCurrentLogsGetter, formattedLogString]);
113	
114	  const appendMessage = React.useCallback(
115	    (containerName: string, blockContent: string, resourceStatus: string) => {
116	      if (blockContent) {
117	        setLogData((prevLogData) => {
118	          if (resourceStatus === 'terminated') {
119	            // Replace the entire content with blockContent
120	            return {
121	              ...prevLogData,
122	              [containerName]: {
123	                logs: [blockContent],
124	                status: resourceStatus,
125	              },
126	            };
127	          } else {
128	            // Otherwise, append the blockContent to the existing logs
129	            const existingLogs = prevLogData[containerName]?.logs || [];
130	            const updatedLogs = [...existingLogs, blockContent.trimEnd()];
131	
132	            return {
133	              ...prevLogData,
134	              [containerName]: {
135	                logs: updatedLogs,
136	                status: resourceStatus,
137	              },
138	            };
139	          }
140	        });
141	      }
142	    },
143	    [],
144	  );
145	
146	  const retryWebSocket = (
147	    watchURL: string,
148	    wsOpts: any,
149	    onMessage: (message: string) => void,
150	    onError: () => void,
151	    retryCount = 0,
152	  ) => {
153	    const ws = new WSFactory(watchURL, wsOpts);
154	    const handleError = () => {
155	      if (retryCount < 5) {
156	        setTimeout(() => {
157	          retryWebSocket(watchURL, wsOpts, onMessage, onError, retryCount + 1);
158	        }, 3000); // Retry after 3 seconds
159	      } else {
160	        onError();
161	      }
162	    };
163	
164	    ws.onmessage((msg) => {
165	      const message = Base64.decode(msg);
166	      onMessage(message);
167	    }).onerror(() => {
168	      handleError();
169	    });
170	
171	    return ws;
172	  };
173	
174	  /* 
175	  Why are we retrying websockets in multicluster ?
176	    Container initialization delays: On spoke clusters, containers may not start immediately after admission
177	    Network latency: Multi-cluster proxy-aae service adds another hop
178	    WebSocket closes early: The connection sometimes closes before the container is ready, requiring retry on onclose
179	  */
180	  const retryMultiClusterWebSocket = (
181	    watchURL: string,
182	    wsOpts: any,
183	    onMessage: (message: string) => void,
184	    onError: () => void,
185	    retryCount = 0,
186	    isFinishedGetter: () => boolean,
187	  ) => {
188	    const mcWs = new WSFactory(watchURL, wsOpts);
189	    let receivedData = false;
190	    let destroyed = false;
191	    let retryScheduled = false;
192	
193	    const handleRetry = () => {
194	      if (destroyed || retryScheduled) return;
195	      retryScheduled = true;
196	      // Stop retrying if PipelineRun has finished
197	      if (isFinishedGetter()) {
198	        return;
199	      }
200	      if (retryCount < 10) {
201	        // Retry up to 10 times (30 seconds total)
202	        setTimeout(() => {
203	          if (!destroyed && !isFinishedGetter()) {
204	            retryMultiClusterWebSocket(
205	              watchURL,
206	              wsOpts,
207	              onMessage,
208	              onError,
209	              retryCount + 1,
210	              isFinishedGetter,
211	            );
212	          }
213	        }, 3000);
214	      } else {
215	        onError();
216	      }
217	    };
218	
219	    // Multi-cluster logs are plain text, not base64 encoded
220	    mcWs
221	      .onopen(() => {})
222	      .onmessage((msg) => {
223	        receivedData = true;
224	        onMessage(msg);
225	      })
226	      .onerror((err) => {
227	        console.error('MC WebSocket ERROR:', err);
228	        handleRetry();
229	      })
230	      .onclose(() => {
231	        // Retry on close if we never received any data (container likely initializing)
232	        if (!receivedData) {
233	          handleRetry();
234	        }
235	      });
236	
237	    // Override destroy to prevent retries after cleanup
238	    const originalDestroy = mcWs.destroy.bind(mcWs);
239	    mcWs.destroy = () => {
240	      destroyed = true;
241	      originalDestroy();
242	    };
243	
244	    return mcWs;
245	  };
246	
247	  React.useEffect(() => {
248	    containers.forEach((container) => {
249	      if (activeContainers.has(container.name)) return;
250	      setActiveContainers((prev) => new Set(prev).add(container.name));
251	      let loaded = false;
252	      let ws: WSFactory;
253	      let mcWs: WSFactory;
254	      const { name } = container;
255	
256	      // Build URL based on hub cluster vs local cluster
257	      const k8sUrlOpts = {
258	        ns: resNamespace,
259	        name: resName,
260	        path: 'log',
261	        queryParams: {
262	          container: name,
263	          follow: 'true',
264	          timestamps: 'true',
265	        },
266	      };
267	      const k8sWatchURL = resourceURL(PodModel, k8sUrlOpts);
268	
269	      const containerStatus: ContainerStatus[] =
270	        resource?.status?.containerStatuses ?? [];
271	      const statusIndex = containerStatus.findIndex(
272	        (c) => c.name === container.name,
273	      );
274	      const resourceStatus = containerToLogSourceStatus(
275	        containerStatus[statusIndex],
276	      );
277	
278	      // Use HTTP fetch for completed PipelineRuns or terminated containers
279	      // Use WebSocket only for actively running containers
280	      const shouldUseHttp =
281	        resourceStatus === LOG_SOURCE_TERMINATED ||
282	        (isResourceManagedByKueue && pipelineRunFinished);
283	
284	      if (shouldUseHttp) {
285	        // Fetch complete logs via HTTP
286	        const logsUrl =
287	          isResourceManagedByKueue && pipelineRunName
288	            ? getMultiClusterLogsUrl(
289	                resNamespace,
290	                pipelineRunName,
291	                resName,
292	                name,
293	              )
294	            : k8sWatchURL;
295	
296	        consoleFetchText(logsUrl)
297	          .then((res) => {
298	            if (loaded) return;
299	            appendMessage(name, res, resourceStatus);
300	          })
301	          .catch((err) => {
302	            if (loaded) return;
303	            setError(true);
304	          });
305	      } else {
306	        // Stream logs via WebSocket for running containers
307	        if (isResourceManagedByKueue && pipelineRunName) {
308	          // Use multi-cluster WebSocket for hub clusters
309	          const mcWsPath = getMultiClusterLogsStreamPath(
310	            resNamespace,
311	            pipelineRunName,
312	            resName,
313	            name,
314	          );
315	          const mcWsOpts = {
316	            host: 'auto',
317	            path: mcWsPath,
318	            subprotocols: ['binary.k8s.io'],
319	          };
320	          mcWs = retryMultiClusterWebSocket(
321	            mcWsPath,
322	            mcWsOpts,
323	            (message) => {
324	              if (loaded) return;
325	              setError(false);
326	              appendMessage(name, message, resourceStatus);
327	            },
328	            () => {
329	              if (loaded) return;
330	              setError(true);
331	            },
332	            0,
333	            () => pipelineRunFinishedRef.current,
334	          );
335	        } else {
336	          // Use k8s WebSocket for local clusters
337	          const wsOpts = {
338	            host: 'auto',
339	            path: k8sWatchURL,
340	            subprotocols: ['base64.binary.k8s.io'],
341	          };
342	          ws = retryWebSocket(
343	            k8sWatchURL,
344	            wsOpts,
345	            (message) => {
346	              if (loaded) return;
347	              setError(false);
348	              appendMessage(name, message, resourceStatus);
349	            },
350	            () => {
351	              if (loaded) return;
352	              setError(true);
353	            },
354	          );
355	        }
356	      }
357	      return () => {
358	        loaded = true;
359	        if (ws) {
360	          ws.destroy();
361	        }
362	        if (mcWs) {
363	          mcWs.destroy();
364	        }
365	      };
366	    });
367	  }, [
368	    resName,
369	    resNamespace,
370	    resource?.status?.containerStatuses,
371	    activeContainers,
372	    isResourceManagedByKueue,
373	    pipelineRunName,
374	    pipelineRunFinished,
375	  ]);
376	
377	  React.useEffect(() => {
378	    const formattedString = processLogData(logData, containers);
379	    const targetRow = findTargetRowForActiveStep(formattedString);
380	    if (typeof targetRow === 'number') {
381	      setScrollToRow(targetRow);
382	      const searchTerm = `STEP-${activeStep}`.toUpperCase();
383	      const formattedStringAfterHighlighting = formattedString.replace(
384	        new RegExp(`(${searchTerm})`, 'gi'),
385	        '\x1b[48;2;253;240;171m\x1b[38;2;21;21;21m$1\x1b[0m',
386	      ); // yellow background with dark text
387	      setFormattedLogString(formattedStringAfterHighlighting);
388	      let isHighlighted = true;
389	      const blinkInterval = setInterval(() => {
390	        if (isHighlighted) {
391	          setFormattedLogString(formattedString);
392	        } else {
393	          setFormattedLogString(formattedStringAfterHighlighting);
394	        }
395	        isHighlighted = !isHighlighted;
396	      }, 300);
397	      const stopBlinkingTimeout = setTimeout(() => {
398	        clearInterval(blinkInterval);
399	        setFormattedLogString(formattedString);
400	      }, 1000);
401	      return () => {
402	        clearInterval(blinkInterval);
403	        clearTimeout(stopBlinkingTimeout);
404	      };
405	    } else {
406	      const totalLines = formattedString.split('\n').length;
407	      setScrollToRow(totalLines);
408	      setFormattedLogString(formattedString);
409	    }
410	  }, [logData, activeStep, findTargetRowForActiveStep]);
411	
412	  return (
413	    <div className="pf-v6-u-h-100 pf-v6-u-w-100">
414	      {error && (
415	        <Alert
416	          variant="danger"
417	          isInline
418	          title={t('An error occurred while retrieving the requested logs.')}
419	        />
420	      )}
421	      <LogViewer
422	        useAnsiClasses={true}
423	        header={
424	          <Banner className="pf-v6-l-flex pf-v5-l-gap-md">
425	            <span data-test-id="logs-taskName" className="pf-v6-u-font-size-md">
426	              {taskName}
427	            </span>
428	            {stillFetching ? (
429	              <span data-test-id="loading-indicator">
430	                <LoadingInline />
431	              </span>
432	            ) : null}
433	          </Banner>
434	        }
435	        hasLineNumbers={false}
436	        isTextWrapped={false}
437	        data={
438	          error
439	            ? t('An error occurred while retrieving the requested logs.')
440	            : formattedLogString
441	        }
442	        theme="dark"
443	        scrollToRow={scrollToRow}
444	        height="100%"
445	      />
446	    </div>
447	  );
448	};
449	
450	export default Logs;

